final:
module top_module(
    input clk,
    input parallel_load,
    input [3:0] in,
    output reg out
);reg [3:0] load_reg;

always @(posedge clk) begin
    if (parallel_load) begin
        load_reg <= in;
    end else begin
        load_reg <= {load_reg[2:0], load_reg[3]};
    end
end

assign out = load_reg[0];

endmodule
